#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *a = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &a[i]);
        long long *pref = (long long*)malloc(N * sizeof(long long));
        long long *suff = (long long*)malloc(N * sizeof(long long));
        long long cur = 0;
        for (int i = 0; i < N; ++i) {
            if (a[i] > cur) cur = a[i];
            pref[i] = cur;
        }
        cur = 0;
        for (int i = N-1; i >= 0; --i) {
            if (a[i] > cur) cur = a[i];
            suff[i] = cur;
        }
        long long ans = 0;
        for (int i = 0; i < N; ++i) {
            long long v = pref[i] < suff[i] ? pref[i] : suff[i];
            ans += v;
        }
        printf("%lld\n", ans);
        free(a); free(pref); free(suff);
    }
    return 0;
}

